import boto3

def create_sns_subscription(topic_arn):
    user_input = input("Please enter your URL for SNS subscription: ")
    sns_client = boto3.client('sns')
    try:
        response = sns_client.subscribe(
            TopicArn=topic_arn,
            Protocol='https',
            Endpoint=user_input
        )
        print(f'Subscription created successfully. Subscription ARN: {response["SubscriptionArn"]}')
    except Exception as e:
        print(f'Error creating subscription: {e}')

if __name__ == "__main__":
    topic_arn = "your-topic-arn"  # Replace with your SNS Topic ARN
    create_sns_subscription(topic_arn)